```go
package main

import (
	"crypto/rand"
	"crypto/rsa"
	"crypto/x509"
	"encoding/pem"
	"fmt"
	"os"
)

func generateRSAKeyPair() {
	// Generate a new RSA private key
	privateKey, err := rsa.GenerateKey(rand.Reader, 2048)
	if err != nil {
		fmt.Println("Error generating RSA private key:", err)
		return
	}

	// Encode the private key to PEM format
	privateKeyPEM := &pem.Block{
		Type:  "RSA PRIVATE KEY",
		Bytes: x509.MarshalPKCS1PrivateKey(privateKey),
	}

	// Write the private key to a file
	privateKeyFile, err := os.Create("private_key.pem")
	if err != nil {
		fmt.Println("Error creating private key file:", err)
		return
	}
	defer privateKeyFile.Close()

	err = pem.Encode(privateKeyFile, privateKeyPEM)
	if err != nil {
		fmt.Println("Error writing private key to file:", err)
		return
	}

	// Generate the public key from the private key
	publicKey := &privateKey.PublicKey

	// Encode the public key to PEM format
	publicKeyPEM := &pem.Block{
		Type:  "RSA PUBLIC KEY",
		Bytes: x509.MarshalPKCS1PublicKey(publicKey),
	}

	// Write the public key to a file
	publicKeyFile, err := os.Create("public_key.pem")
	if err != nil {
		fmt.Println("Error creating public key file:", err)
		return
	}
	defer publicKeyFile.Close()

	err = pem.Encode(publicKeyFile, publicKeyPEM)
	if err != nil {
		fmt.Println("Error writing public key to file:", err)
		return
	}

	fmt.Println("RSA key pair generated and saved successfully.")
}

func main() {
	generateRSAKeyPair()
}
```

**Explanation**:
This Go function `generateRSAKeyPair` is designed to create an RSA key pair consisting of a private key and a public key. The function uses the `crypto/rsa` package to generate the keys and the `crypto/x509` package to marshal the keys into PEM format. The private key is then written to a file named "private_key.pem", and the public key is written to a file named "public_key.pem". The function handles errors at each step, ensuring that the key pair is generated and saved correctly.

