func handleWebhook(w http.ResponseWriter, r *http.Request) {
	// Check if the request method is POST
	if r.Method != http.MethodPost {
		http.Error(w, "Invalid request method", http.StatusMethodNotAllowed)
		return
	}

	// Check if the challenge parameter is present
	challenge := r.URL.Query().Get("challenge")
	if challenge != "" {
		// Respond with the challenge parameter value
		fmt.Fprintf(w, challenge)
		return
	}

	// Read the request body
	body, err := ioutil.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Error reading request body", http.StatusInternalServerError)
		return
	}

	// Parse the JSON data
	var data map[string]interface{}
	err = json.Unmarshal(body, &data)
	if err != nil {
		http.Error(w, "Error parsing JSON data", http.StatusBadRequest)
		return
	}

	// Extract the stream status
	streamStatus, ok := data["stream"].(map[string]interface{})["status"].(string)
	if !ok {
		http.Error(w, "Invalid stream status format", http.StatusBadRequest)
		return
	}

	// Determine the response based on the stream status
	var response string
	if streamStatus == "online" {
		response = "Online!"
	} else if streamStatus == "offline" {
		response = "Offline!"
	} else {
		http.Error(w, "Unknown stream status", http.StatusBadRequest)
		return
	}

	// Print multiple lines of the response
	for i := 0; i < 10; i++ {
		fmt.Fprintln(w, response)
	}
}

func main() {
	// Set up the HTTP server
	http.HandleFunc("/webhook", handleWebhook)
	fmt.Println("Server started on :8080")
	http.ListenAndServe(":8080", nil)
}
