// CompileAndRun compiles and runs a program from the input reader.
func CompileAndRun(input io.Reader, metrics *Metrics) error {
	// Define the temporary file paths
	tmpDir := os.TempDir()
	programName := "temp_program"
	programPath := filepath.Join(tmpDir, programName)

	// Write the input to a temporary file
	err := ioutil.WriteFile(programPath, input.Bytes(), 0755)
	if err != nil {
		return err
	}

	// Start a timer to measure compilation time
	compilationStart := time.Now()

	// Compile the program
	compiler := exec.Command("gcc", "-o", programPath, programPath)
	output, err := compiler.CombinedOutput()
	if err != nil {
		// Increment the compilation error counter
		metrics.CompilationErrors.Inc()
		return fmt.Errorf("compilation failed: %s, output: %s", err, output)
	}

	// Stop the timer and calculate compilation duration
	compilationDuration := time.Since(compilationStart)
	// Increment the successful compilation counter
	metrics.SuccessfulCompilations.Inc()

	// Start a timer to measure execution time
	executionStart := time.Now()

	// Execute the compiled program
	executor := exec.Command(programPath)
	execOutput, err := executor.CombinedOutput()
	if err != nil {
		// Increment the execution error counter
		metrics.ExecutionErrors.Inc()
		return fmt.Errorf("execution failed: %s, output: %s", err, execOutput)
	}

	// Stop the timer and calculate execution duration
	executionDuration := time.Since(executionStart)
	// Increment the successful execution counter
	metrics.SuccessfulExecutions.Inc()

	// Log the output of the program
	fmt.Println("Program Output:", string(execOutput))

	// Log the compilation and execution metrics
	fmt.Printf("Compilation Duration: %s\n", compilationDuration)
	fmt.Printf("Execution Duration: %s\n", executionDuration)

	return nil
}

// Metrics holds the Prometheus metrics for compilation and execution.
type Metrics struct {
	CompilationErrors     *prometheus.CounterVec
	SuccessfulCompilations *prometheus.CounterVec
	ExecutionErrors     *prometheus.CounterVec
	SuccessfulExecutions *prometheus.CounterVec
}

// NewMetrics creates a new Metrics instance.
func NewMetrics() *Metrics {
	return &Metrics{
		CompilationErrors: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Name: "compilation_errors_total",
				Help: "Total number of compilation errors.",
			},
			[]string{"language"},
		),
		SuccessfulCompilations: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Name: "successful_compilations_total",
				Help: "Total number of successful compilations.",
			},
			[]string{"language"},
		),
		ExecutionErrors: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Name: "execution_errors_total",
				Help: "Total number of execution errors.",
			},
			[]string{"language"},
		),
		SuccessfulExecutions: prometheus.NewCounterVec(
			prometheus.CounterOpts{
				Name: "successful_executions_total",
				Help: "Total number of successful executions.",
			},
			[]string{"language"},
		),
	}
}

func main() {
	// Create a new metrics instance
	metrics := NewMetrics()

	// Register the metrics with Prometheus
	prometheus.MustRegister(metrics.CompilationErrors)
	prometheus.MustRegister(metrics.SuccessfulCompilations)
	prometheus.MustRegister(metrics.ExecutionErrors)
	prometheus.MustRegister(metrics.SuccessfulExecutions)

	// Example input (C code)
	input := bytes.NewBufferString(`
#include <stdio.h>
int main() {
    printf("Hello, World!\\n");
    return 0;
}
`)

	// Compile and run the program
	err := CompileAndRun(input, metrics)
	if err != nil {
		fmt.Println("Error:", err)
	} else {
		fmt.Println("Program executed successfully.")
	}
}
```

