func HandleWebhookCallback(c *gin.Context) {
	// Parse the incoming request body
	var event interface{}
	if err := c.ShouldBindJSON(&event); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": "Invalid request body"})
		return
	}

	// Check if the event is a user follow event
	switch e := event.(type) {
	case UserFollowEvent:
		fmt.Printf("User follow event received: %+v\n", e)
		c.JSON(http.StatusOK, gin.H{"message": "User follow event processed"})
	case ChallengeResponse:
		fmt.Printf("Challenge response received: %+v\n", e)
		c.JSON(http.StatusOK, gin.H{"message": "Challenge response processed"})
	default:
		c.JSON(http.StatusUnsupportedMediaType, gin.H{"error": "Unsupported event type"})
	}
}

func main() {
	// Initialize the Gin router
	router := gin.Default()

	// Define the webhook callback route
	router.POST("/webhook", HandleWebhookCallback)

	// Start the server
	if err := router.Run(":8080"); err != nil {
		fmt.Println("Failed to start server:", err)
	}
}
