package main

import (
	"fmt"
	"net/http"
	"strings"
)

// This map holds the path-encoded identifiers as keys and the original URLs as values.
var urlMap = map[string]string{
	"abc123": "http://example.com",
	"xyz789": "http://example.org",
	// Add more mappings as needed
}

func landingPageHandler(w http.ResponseWriter, r *http.Request) {
	// Extract the path-encoded identifier from the URL path.
	// For simplicity, let's assume the identifier is the first segment of the path.
	identifier := strings.Split(r.URL.Path, "/")[1]

	// Check if the identifier exists in the urlMap.
	if originalURL, ok := urlMap[identifier]; ok {
		// Redirect to the original URL.
		http.Redirect(w, r, originalURL, http.StatusMovedPermanently)
	} else {
		// If the identifier is not found, serve a landing page.
		fmt.Fprintf(w, "Welcome to the landing page!")
	}
}

func main() {
	// Register the landingPageHandler to handle requests to the root URL.
	http.HandleFunc("/", landingPageHandler)

	// Start the HTTP server on port 8080.
	fmt.Println("Starting server at port 8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Println(err)
	}
}
