func NewBasket(name string, config map[string]interface{}) (*Basket, error) {
	if name == "" {
		return nil, errors.New("basket name cannot be empty")
	}
	if len(name) > 255 {
		return nil, errors.New("basket name cannot exceed 255 characters")
	}
	return &Basket{Name: name, Config: config}, nil
}

// TestNewBasket tests the NewBasket function with various scenarios.
func TestNewBasket(t *testing.T) {
	// Test with a valid name and no configuration
	validBasket, err := NewBasket("GroceryBasket", nil)
	if err != nil {
		t.Errorf("Expected no error, got: %v", err)
	}
	if validBasket.Name != "GroceryBasket" {
		t.Errorf("Expected name 'GroceryBasket', got: %s", validBasket.Name)
	}
	if validBasket.Config != nil {
		t.Errorf("Expected nil config, got: %v", validBasket.Config)
	}

	// Test with an empty name
	_, err = NewBasket("", nil)
	if err == nil {
		t.Errorf("Expected error for empty name, got nil")
	}

	// Test with a name exceeding 255 characters
	longName := "a"
	for i := 0; i < 256; i++ {
		longName += "a"
	}
	_, err = NewBasket(longName, nil)
	if err == nil {
		t.Errorf("Expected error for long name, got nil")
	}

	// Test with a valid name and configuration
