```javascript
function appendFileRows() {
    var files = document.getElementById("fileInput").files;
    var table = document.getElementById("fileTable");

    for (var i = 0; i < files.length; i++) {
        var file = files[i];
        var row = table.insertRow(i + 1);
        var cell1 = row.insertCell(0);
        var cell2 = row.insertCell(1);

        cell1.textContent = file.name;
        cell2.textContent = file.size + " bytes";

        var img = document.createElement('img');
        img.style.width = '50px';
        img.style.height = '50px';

        switch (file.type) {
            case 'image/jpeg':
            case 'image/png':
                img.src = 'path/to/jpeg.png'; // Replace with the path to your image for JPEG files
                break;
            case 'application/pdf':
                img.src = 'path/to/pdf.png'; // Replace with the path to your image for PDF files
                break;
            case 'application/msword':
            case 'application/vnd.openxmlformats-officedocument.wordprocessingml.document':
                img.src = 'path/to/docx.png'; // Replace with the path to your image for DOCX files
                break;
            default:
                img.src = 'path/to/unknown.png'; // Replace with the path to your image for unknown file types
                break;
        }

        cell1.appendChild(img);
    }
}
```

