    // Function to filter options based on search input
    function filterOptions() {
        const searchText = searchInput.value.toLowerCase();
        const options = selectElement.querySelectorAll('option');
        options.forEach(option => {
            if (option.textContent.toLowerCase().includes(searchText)) {
                option.style.display = '';
            } else {
                option.style.display = 'none';
            }
        });
    }

    // Event listener for search input
    if (searchEnabled) {
        searchInput.addEventListener('input', filterOptions);
    }

    // Function to group options if groupBy is specified
    function groupOptions() {
        const groups = {};
        const options = selectElement.querySelectorAll('option');
        options.forEach(option => {
            const groupKey = option.getAttribute(groupBy);
            if (!groups[groupKey]) {
                groups[groupKey] = document.createElement('optgroup');
                groups[groupKey].label = groupKey;
                selectElement.appendChild(groups[groupKey]);
            }
            groups[groupKey].appendChild(option);
        });
    }

    // Apply grouping if specified
    if (groupBy) {
        groupOptions();
    }
}

