                        focusableElement.focus();
                    }
                };

                focusPrevious = function () {
                    currentIndex--;
                    if (currentIndex < 0) {
                        currentIndex = numElements - 1;
                    }

                    focus();

                    return false;
                };

                focusNext = function () {
                    currentIndex++;
                    if (currentIndex >= numElements) {
                        currentIndex = 0;
                    }

                    focus();

                    return false;
