HTML:
```html
<div id="messageContainer" style="display: none; position: absolute; background-color: #f44336; color: white; padding: 10px; border-radius: 5px;">
    This is a sliding message.
</div>
<button onclick="showMessage()">Show Message</button>
```

CSS:
```css
#messageContainer {
    transition: all 0.5s ease-in-out;
}
```

JavaScript:
```javascript
function showMessage() {
    var messageContainer = document.getElementById('messageContainer');
    messageContainer.style.display = 'block'; // Show the message
    messageContainer.style.transform = 'translateY(0)'; // Slide in from below

    setTimeout(function() {
        messageContainer.style.transform = 'translateY(-100%)'; // Slide out
        setTimeout(function() {
            messageContainer.style.display = 'none'; // Hide the message after sliding out
        }, 500); // Wait for the sliding out transition to complete
    }, 2000); // Show the message for 2 seconds before hiding
}
```

