function searchAll() {
    var keyword = document.getElementById('search-input').value;
    if (keyword) {
        // Update the URL with the search keyword
        window.history.pushState({ page: 'search', keyword: keyword }, 'Search Results', '?search=' + encodeURIComponent(keyword));

        // Fetch and display search results for members and entities
        var searchUrl = '/search?search=' + encodeURIComponent(keyword);
        fetch(searchUrl)
            .then(response => response.json())
            .then(data => {
                var members = data.members;
                var entities = data.entities;

                // Clear previous results
                document.getElementById('members-results').innerHTML = '';
                document.getElementById('entities-results').innerHTML = '';

                // Display members results
                members.forEach(member => {
                    var memberElement = document.createElement('div');
                    memberElement.className = 'member-result';
                    memberElement.innerHTML = `
                        <img src="${member.avatar}" alt="${member.name}">
                        <h3>${member.name}</h3>
                        <p>${member.description}</p>
                    `;
                    document.getElementById('members-results').appendChild(memberElement);
                });

                // Display entities results
                entities.forEach(entity => {
                    var entityElement = document.createElement('div');
                    entityElement.className = 'entity-result';
                    entityElement.innerHTML = `
                        <img src="${entity.thumbnail}" alt="${entity.name}">
                        <h3>${entity.name}</h3>
                        <p>${entity.description}</p>
                    `;
                    document.getElementById('entities-results').appendChild(entityElement);
                });
            })
            .catch(error => {
                console.error('Error fetching search results:', error);
            });
    }
}
