```javascript
$(document).ready(function() {
    // Listen for input event on the name input field
    $('#nameInput').on('input', function() {
        var name = $(this).val(); // Get the value from the input field
        // Update the contact list based on the name
        updateContactList(name);
    });

    function updateContactList(name) {
        // Assuming you have a list of contacts and you want to filter them based on the name
        var contacts = [
            { id: 1, name: 'John Doe', email: 'john@example.com' },
            { id: 2, name: 'Jane Doe', email: 'jane@example.com' },
            // Add more contacts here
        ];

        var filteredContacts = contacts.filter(contact => contact.name.toLowerCase().includes(name.toLowerCase()));

        // Clear the existing contact list
        $('#contactList').empty();

        // Add the filtered contacts to the contact list
        filteredContacts.forEach(contact => {
            $('#contactList').append(`<li>${contact.name} - ${contact.email}</li>`);
        });
    }
});
```

In this example, we're assuming you have an input field with the ID `nameInput` and a list with the ID `contactList`. The `updateContactList` function filters the contacts based on the name entered in the input field and updates the list accordingly.

