// Define the function to handle the conversation title update
function updateConversationTitle(conversationId, newTitle) {
  // Check if the new title is valid (not empty)
  if (!newTitle.trim()) {
    alert("Title cannot be empty. Please enter a valid title.");
    return;
  }

  // Prepare the data to be sent to the server
  var data = {
    conversationId: conversationId,
    title: newTitle
  };

  // Send the data to the server using an AJAX POST request
  $.ajax({
    url: 'updateConversationTitle',
    type: 'POST',
    data: data,
    success: function(response) {
      // If the update is successful, display a success message
      alert("Conversation title updated successfully.");
    },
    error: function(xhr, status, error) {
      // If there is an error during the update, display an error message
      alert("Failed to update conversation title: " + error);
    }
  });
}

