function generateHTMLList(results) {
    if (!Array.isArray(results) || results.length === 0) {
        return '<ul></ul>';
    }

    let html = '<ul>';

    results.forEach(item => {
        if (typeof item === 'object' && item !== null && 'text' in item && 'link' in item) {
            html += `<li><a href="${item.link}" target="_blank">${item.text}</a></li>`;
        } else {
            console.warn('Invalid item in results array:', item);
        }
    });

    html += '</ul>';

    return html;
}

// Example usage:
const results = [
    { text: 'Google', link: 'https://www.google.com' },
    { text: 'Alibaba Cloud', link: 'https://www.aliyun.com' },
    { text: 'Stack Overflow', link: 'https://stackoverflow.com' }
];

const htmlList = generateHTMLList(results);
console.log(htmlList);
