// Function to create a checkbox list item
function createCheckboxListItem(element, checked) {
  // Create a new div element
  const checkboxItem = document.createElement('div');
  checkboxItem.className = 'checkbox-item';

  // Create a checkbox input element
  const checkbox = document.createElement('input');
  checkbox.type = 'checkbox';
  checkbox.checked = checked; // Set the checked state based on the input
  checkboxItem.appendChild(checkbox);

  // Create a label for the checkbox
  const label = document.createElement('label');
  label.textContent = element.label; // Assuming the element has a label property
  checkboxItem.appendChild(label);

  // Append the checkbox item to the parent element
  element.parentNode.appendChild(checkboxItem);

  // Add an event listener to handle checkbox change
  checkbox.addEventListener('change', function() {
    if (checkbox.checked) {
      console.log('Checkbox is checked:', element.id); // Log the ID of the element when checked
    } else {
      console.log('Checkbox is unchecked:', element.id); // Log the ID of the element when unchecked
    }
  });

  return checkboxItem;
}
```

