type Weather struct {
	Main struct {
		Temp float64 `json:"temp"`
	} `json:"main"`
	Weather []struct {
		Description string `json:"description"`
	} `json:"weather"`
}

// Get fetches weather data from an API using latitude, longitude, and timestamp
func Get(latitude, longitude, timestamp string) (*Weather, error) {
	url := fmt.Sprintf("http://api.weatherapi.com/v1/current.json?key=YOUR_API_KEY&q=%s,%s&dt=%s", latitude, longitude, timestamp)
	resp, err := http.Get(url)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	var weather Weather
	if err := json.NewDecoder(resp.Body).Decode(&weather); err != nil {
		return nil, err
	}

	return &weather, nil
}

func main() {
	latitude := "34.0522"
	longitude := "-118.2437"
	timestamp := "1609459200" // Unix timestamp for 2021-01-01

	weather, err := Get(latitude, longitude, timestamp)
	if err != nil {
		fmt.Println("Error fetching weather:", err)
		return
	}

	fmt.Printf("Temperature: %.2f°C, Weather: %s\n", weather.Main.Temp, weather.Weather[0].Description)
}
