const PDFDocument = require('pdf-lib');

/**
 * Retrieves information about a PDF file.
 * @param {string|Buffer} pdfData - The PDF file data as a string or Buffer.
 * @param {boolean} [async=false] - Whether to perform the operation asynchronously.
 * @returns {Promise<Object>|Object} - A Promise that resolves to the PDF information or the PDF information itself if synchronous.
 */
async function pdfinfo(pdfData, async = false) {
  try {
    if (async) {
      const pdfDoc = await PDFDocument.load(pdfData);
      const info = pdfDoc.getInfo();
      return info;
    } else {
      const pdfDoc = await PDFDocument.load(pdfData);
      const info = pdfDoc.getInfo();
      return info;
    }
  } catch (error) {
    throw new Error(`Failed to retrieve PDF information: ${error.message}`);
  }
}

