To retrieve block device information in Node.js, you can use the `fs` and `child_process` modules to interact with the system's block device files. Below is an example function that retrieves block device information, with options to ignore certain devices and majors:

```javascript
const fs = require('fs');
const childProcess = require('child_process');

function getBlockDeviceInfo(options = {}) {
  const { ignoreDevices = [], ignoreMajors = [] } = options;
  const blockDevices = [];

  // Function to check if a device should be ignored
  function shouldIgnoreDevice(device) {
    return ignoreDevices.includes(device) || ignoreMajors.includes(device.major);
  }

  // Read the block devices from /sys/block
  const blockDir = '/sys/block';
  fs.readdirSync(blockDir).forEach(device => {
    const devicePath = `${blockDir}/${device}`;
    if (fs.statSync(devicePath).isDirectory()) {
      const deviceInfo = {
        name: device,
        path: devicePath,
        major: parseInt(fs.readFileSync(`${devicePath}/dev`, 'utf8').split(':')[0], 10),
        minor: parseInt(fs.readFileSync(`${devicePath}/dev`, 'utf8').split(':')[1], 10),
        size: parseInt(fs.readFileSync(`${devicePath}/size`, 'utf8'), 10) * 512 // Convert sectors to bytes
      };

      if (!shouldIgnoreDevice(deviceInfo)) {
        blockDevices.push(deviceInfo);
      }
    }
  });

  return blockDevices;
}

// Example usage
getBlockDeviceInfo({ ignoreDevices: ['loop0'], ignoreMajors: [253] })
  .then(devices => {
    console.log(devices);
  })
  .catch(error => {
    console.error('Error retrieving block device information:', error);
  });
```

This function reads the block devices from the `/sys/block` directory, extracts the necessary information (name, path, major, minor, and size), and filters out the devices based on the provided options. The size is calculated in bytes by converting the number of sectors to bytes.

You can use this function to retrieve block device information and filter out specific devices or majors as needed.

