```javascript
const { exec } = require('child_process');

function executeBinary(binaryPath, args, expectedErrorString, callback) {
  const command = `${binaryPath} ${args.join(' ')}`;

  exec(command, (error, stdout, stderr) => {
    if (error) {
      if (stderr.includes(expectedErrorString)) {
        callback(null);
      } else {
        callback(new Error(`Expected error string "${expectedErrorString}" not found in stderr: ${stderr}`));
      }
    } else {
      callback(new Error(`No error occurred, but expected error string "${expectedErrorString}" not found in stderr: ${stderr}`));
    }
  });
}

// Example usage:
executeBinary('path/to/binary', ['arg1', 'arg2'], 'Expected error message', (error) => {
  if (error) {
    console.error('Error:', error.message);
  } else {
    console.log('Test passed!');
  }
});
```

This function takes four arguments:

1. `binaryPath`: The path to the binary you want to execute.
2. `args`: An array of arguments to pass to the binary.
3. `expectedErrorString`: The specific error message you expect to find in the binary's error output.
4. `callback`: A callback function that will be called with an error if the expected error string is not found, or `null` if the test passes.

The function constructs the command to execute the binary with the provided arguments, then uses the `exec` function to run the command. If an error occurs during execution, it checks if the error output contains the expected error string. If it does, the callback is called with `null`. If it doesn't, the callback is called with an error message. If no error occurs during execution, but the expected error string is not found in the error output, the callback is called with an error message.

