const { exec } = require('child_process');

function rsync(source, destination, callback) {
    const rsyncCommand = `rsync -avz ${source} ${destination}`;

    exec(rsyncCommand, (error, stdout, stderr) => {
        if (error) {
            console.error(`Error executing rsync: ${error.message}`);
            callback(error);
            return;
        }
        if (stderr) {
            console.error(`rsync stderr: ${stderr}`);
            callback(stderr);
            return;
        }
        console.log(`rsync stdout: ${stdout}`);
        callback(null, stdout);
    });
}

// Usage
rsync('/path/to/source', '/path/to/destination', (error, stdout) => {
    if (error) {
        console.error('Rsync operation failed:', error);
        return;
    }
    console.log('Rsync operation successful:', stdout);
});
```

