import configparser

class ConfigFileNotFoundError(Exception):
    pass

class ConfigSectionNotFoundError(Exception):
    pass

class ConfigOptionNotFoundError(Exception):
    pass

class ConfigLoader:
    def __init__(self, filename):
        self.filename = filename
        self.config = configparser.ConfigParser()

    def load_config(self):
        try:
            self.config.read(self.filename)
        except FileNotFoundError:
            raise ConfigFileNotFoundError(f"Configuration file '{self.filename}' not found.")

    def get_option(self, section, option):
        try:
            return self.config.get(section, option)
        except configparser.NoSectionError:
            raise ConfigSectionNotFoundError(f"Section '{section}' not found in the configuration file.")
        except configparser.NoOptionError:
            raise ConfigOptionNotFoundError(f"Option '{option}' not found in section '{section}'.")

# Example usage
config_loader = ConfigLoader('config.ini')
config_loader.load_config()
database_host = config_loader.get_option('Database', 'Host')
database_port = config_loader.get_option('Database', 'Port')
```

