Here's a simple React component that displays user profile information, page details, and lists of linked entities with user contributions. This is a basic example and can be expanded based on the specific requirements.

```jsx
import React from 'react';

class UserProfile extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      userProfile: {},
      pageDetails: {},
      linkedEntities: [],
      userContributions: []
    };
  }

  componentDidMount() {
    // Fetch user profile, page details, linked entities and user contributions from API
    fetch('https://api.example.com/userProfile')
      .then(response => response.json())
      .then(data => this.setState({ userProfile: data }));

    fetch('https://api.example.com/pageDetails')
      .then(response => response.json())
      .then(data => this.setState({ pageDetails: data }));

    fetch('https://api.example.com/linkedEntities')
      .then(response => response.json())
      .then(data => this.setState({ linkedEntities: data }));

    fetch('https://api.example.com/userContributions')
      .then(response => response.json())
      .then(data => this.setState({ userContributions: data }));
  }

  render() {
    return (
      <div>
        <h1>User Profile</h1>
        <p>Name: {this.state.userProfile.name}</p>
        <p>Email: {this.state.userProfile.email}</p>

        <h1>Page Details</h1>
        <p>Title: {this.state.pageDetails.title}</p>
        <p>Description: {this.state.pageDetails.description}</p>

        <h1>Linked Entities</h1>
        <ul>
          {this.state.linkedEntities.map(entity => (
            <li key={entity.id}>{entity.name}</li>
          ))}
        </ul>

        <h1>User Contributions</h1>
        <ul>
          {this.state.userContributions.map(contribution => (
            <li key={contribution.id}>{contribution.title}</li>
          ))}
        </ul>
      </div>
    );
  }
}

export default UserProfile;
```

