Here is a simple example of how you can create a Go HTTP handler that retrieves and returns the last 'n' daily tallies as a JSON array from a database using a URL parameter. For this example, we will use SQLite as the database.

```go
package main

import (
	"database/sql"
	"encoding/json"
	"log"
	"net/http"
	"strconv"

	_ "github.com/mattn/go-sqlite3"
)

type DailyTally struct {
	ID   int
	Date string
	Tally int
}

func getDailyTallies(w http.ResponseWriter, r *http.Request) {
	// Parse the 'n' parameter from the URL
	nStr := r.URL.Query().Get("n")
	n, err := strconv.Atoi(nStr)
	if err != nil {
		http.Error(w, "Invalid 'n' parameter", http.StatusBadRequest)
		return
	}

	// Open a connection to the SQLite database
	db, err := sql.Open("sqlite3", "./daily_tallies.db")
	if err != nil {
		http.Error(w, "Failed to open database", http.StatusInternalServerError)
		return
	}
	defer db.Close()

	// Query the database for the last 'n' daily tallies
	rows, err := db.Query("SELECT id, date, tally FROM daily_tallies ORDER BY date DESC LIMIT ?", n)
	if err != nil {
		http.Error(w, "Failed to query database", http.StatusInternalServerError)
		return
	}
	defer rows.Close()

	// Parse the rows into a slice of DailyTally structs
	var tallies []DailyTally
	for rows.Next() {
		var tally DailyTally
		err := rows.Scan(&tally.ID, &tally.Date, &tally.Tally)
		if err != nil {
			http.Error(w, "Failed to scan row", http.StatusInternalServerError)
			return
		}
		tallies = append(tallies, tally)
	}

	// Return the tallies as a JSON array
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(tallies)
}

func main() {
	http.HandleFunc("/daily_tallies", getDailyTallies)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

In this example, we first parse the 'n' parameter from the URL. Then, we open a connection to the SQLite database and query the last 'n' daily tallies. The results are then parsed into a slice of DailyTally structs, which is returned as a JSON array.

