```go
package main

import (
	"database/sql"
	"fmt"
	"net/http"

	_ "github.com/go-sql-driver/mysql"
)

func main() {
	http.HandleFunc("/fetch", fetchRecord)
	http.ListenAndServe(":8080", nil)
}

func fetchRecord(w http.ResponseWriter, r *http.Request) {
	// Connect to the MySQL database
	db, err := sql.Open("mysql", "user:password@tcp(127.0.0.1:3306)/dbname")
	if err != nil {
		http.Error(w, "Error connecting to database", http.StatusInternalServerError)
		return
	}
	defer db.Close()

	// Check if the database connection is successful
	err = db.Ping()
	if err != nil {
		http.Error(w, "Error pinging database", http.StatusInternalServerError)
		return
	}

	// Get parameters from HTTP request
	id := r.URL.Query().Get("id")
	if id == "" {
		http.Error(w, "ID parameter is required", http.StatusBadRequest)
		return
	}

	// Prepare SQL query
	query := "SELECT * FROM tablename WHERE id = ?"
	stmt, err := db.Prepare(query)
	if err != nil {
		http.Error(w, "Error preparing SQL query", http.StatusInternalServerError)
		return
	}
	defer stmt.Close()

	// Execute SQL query
	var result string
	err = stmt.QueryRow(id).Scan(&result)
	if err != nil {
		if err == sql.ErrNoRows {
			http.Error(w, "No record found", http.StatusNotFound)
		} else {
			http.Error(w, "Error fetching record", http.StatusInternalServerError)
		}
		return
	}

	// Display the fetched record
	fmt.Fprintf(w, "Record: %s", result)
}
```

