To display the contents of a specified database table in a web page using Go, you would typically use a web framework like Gin or Echo, along with a database driver like `database/sql` and a specific driver for your database (e.g., `lib/pq` for PostgreSQL, `go-sql-driver/mysql` for MySQL). Below is an example using Gin and PostgreSQL:

```go
package main

import (
	"database/sql"
	"log"

	"github.com/gin-gonic/gin"
	_ "github.com/lib/pq"
)

func main() {
	// Database connection string
	db, err := sql.Open("postgres", "user=yourusername dbname=yourdbname sslmode=disable")
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	// Check if the connection is successful
	err = db.Ping()
	if err != nil {
		log.Fatal(err)
	}

	// Set up Gin router
	r := gin.Default()

	// Define a route to display the table contents
	r.GET("/table/:tablename", func(c *gin.Context) {
		tablename := c.Param("tablename")

		// Query the database
		rows, err := db.Query("SELECT * FROM " + tablename)
		if err != nil {
			c.JSON(500, gin.H{"error": err.Error()})
			return
		}
		defer rows.Close()

		// Get column names
		columns, err := rows.Columns()
		if err != nil {
			c.JSON(500, gin.H{"error": err.Error()})
			return
		}

		// Create a slice to hold the data
		values := make([]interface{}, len(columns))
		valuePtrs := make([]interface{}, len(columns))

		for rows.Next() {
			for i := range columns {
				valuePtrs[i] = &values[i]
			}
			err := rows.Scan(valuePtrs...)
			if err != nil {
				c.JSON(500, gin.H{"error": err.Error()})
				return
			}

			// Print the values
			for i, col := range columns {
				val := values[i]
				b, ok := val.([]byte)
				if ok {
					val = string(b)
				}
				log.Printf("%s: %v\n", col, val)
			}
		}

		// Check for errors from iterating over rows
		err = rows.Err()
		if err != nil {
			c.JSON(500, gin.H{"error": err.Error()})
			return
		}

		// Send a success response
		c.JSON(200, gin.H{"message": "Table contents retrieved successfully"})
	})

	// Start the server
	r.Run(":8080")
}
```

