}

# Decorator to check if user is logged in
def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'user_id' not in session:
            return jsonify({'error': 'Unauthorized'}), 401
        return f(*args, **kwargs)
    return decorated_function

# Decorator to check if user is authorized to edit another user's profile
def authorized_user(f):
    @wraps(f)
    def decorated_function(user_id, *args, **kwargs):
        if 'user_id' not in session or session['user_id'] != user_id:
            return jsonify({'error': 'Unauthorized'}), 403
        return f(user_id, *args, **kwargs)
    return decorated_function

@app.route('/edit_user/<user_id>', methods=['PUT'])
@login_required
@authorized_user
def edit_user(user_id):
    data = request.get_json()
    if 'name' in data and 'email' in data:
        users[user_id]['name'] = data['name']
        users[user_id]['email'] = data['email']
        return jsonify({'message': 'User settings updated successfully'}), 200
    else:
        return jsonify({'error': 'Invalid data'}), 400

if __name__ == '__main__':
    app.run(debug=True)
