```ruby
require 'elasticsearch'

# Initialize Elasticsearch client
client = Elasticsearch::Client.new(log: true)

# Define the method for searching taxonomic data
def search_taxonomic_data(client, query, page = 1, per_page = 10, order = 'asc', include_synonyms = false, include_images = false)
  # Initialize the search parameters
  params = {
    index: 'taxonomic_data',
    body: {
      query: {
        multi_match: {
          query: query,
          fields: ['name^2', 'description']
        }
      },
      from: (page - 1) * per_page,
      size: per_page,
      sort: [
        { name: { order: order } }
      ]
    }
  }

  # Add optional parameters to the query
  params[:body][:query][:bool] = {
    must: [
      { match_all: {} }
    ]
  }
  params[:body][:query][:bool][:must].push({ term: { include_synonyms: include_synonyms } }) if include_synonyms
  params[:body][:query][:bool][:must].push({ term: { include_images: include_images } }) if include_images

  # Execute the search
  response = client.search(params)

  # Return the search results
  response['hits']['hits']
end

# Example usage:
results = search_taxonomic_data(client, 'Homo sapiens', page: 1, per_page: 5, order: 'desc', include_synonyms: true, include_images: false)
puts results
```

