import java.io.*;
import java.util.zip.*;

public class UnzipResource {

    /**
     * Unzips a resource from the classpath into the specified output folder.
     *
     * @param resourcePath The path of the resource to unzip (e.g., "/path/to/yourfile.zip").
     * @param outputFolder The path of the output folder where the contents will be extracted.
     * @throws IOException If an I/O error occurs during the unzipping process.
     */
    public static void unzipResource(String resourcePath, String outputFolder) throws IOException {
        // Ensure the output folder exists
        File outputDir = new File(outputFolder);
        if (!outputDir.exists()) {
            outputDir.mkdirs();
        }

        // Get the input stream for the resource
        InputStream inputStream = UnzipResource.class.getResourceAsStream(resourcePath);
        if (inputStream == null) {
            throw new FileNotFoundException("Resource not found: " + resourcePath);
        }

        // Create a ZipInputStream to read the ZIP file
        ZipInputStream zipInputStream = new ZipInputStream(inputStream);
        ZipEntry zipEntry = zipInputStream.getNextEntry();

        // Process each entry in the ZIP file
        while (zipEntry != null) {
            String entryName = zipEntry.getName();
            File entryFile = new File(outputFolder, entryName);

            // If it's a directory, create it
            if (zipEntry.isDirectory()) {
                entryFile.mkdirs();
            } else {
                // Create the parent directory if it doesn't exist
                File parentDir = entryFile.getParentFile();
                if (parentDir != null && !parentDir.exists()) {
                    parentDir.mkdirs();
                }

                // Write the file to the output directory
                try (OutputStream outputStream = new FileOutputStream(entryFile)) {
                    byte[] buffer = new byte[1024];
                    int bytesRead;
                    while ((bytesRead = zipInputStream.read(buffer)) != -1) {
                        outputStream.write(buffer, 0, bytesRead);
                    }
                }
            }

            // Move to the next entry
            zipInputStream.closeEntry();
            zipEntry = zipInputStream.getNextEntry();
        }

        // Close the ZipInputStream
        zipInputStream.close();
    }

    public static void main(String[] args) {
        try {
            // Example usage
            unzipResource("/path/to/yourfile.zip", "/path/to/output/folder");
            System.out.println("Unzipping completed successfully.");
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}
