```java
import org.apache.commons.compress.archivers.zip.ZipArchiveEntry;
import org.apache.commons.compress.archivers.zip.ZipFile;
import org.apache.commons.compress.archivers.zip.ZipArchiveOutputStream;

import java.io.*;
import java.util.Enumeration;

public class NetBeansModuleManager {

    private static final String MODULE_DIR = "path/to/your/module";

    public static void main(String[] args) {
        String zipFile = "path/to/your/module.zip";

        // Package module
        packageModule(MODULE_DIR, zipFile);

        // Unpack module
        unpackModule(zipFile, MODULE_DIR);
    }

    public static void packageModule(String moduleDir, String zipFile) {
        try (ZipArchiveOutputStream zos = new ZipArchiveOutputStream(new FileOutputStream(zipFile))) {
            File module = new File(moduleDir);
            File[] files = module.listFiles();

            if (files != null) {
                for (File file : files) {
                    addFileToZip(zos, file, moduleDir);
                }
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private static void addFileToZip(ZipArchiveOutputStream zos, File file, String parentDir) throws IOException {
        String entryName = file.getPath().substring(parentDir.length() + 1);
        ZipArchiveEntry zipEntry = new ZipArchiveEntry(entryName);
        zos.putArchiveEntry(zipEntry);

        if (file.isFile()) {
            try (InputStream fis = new FileInputStream(file)) {
                byte[] buffer = new byte[1024];
                int len;
                while ((len = fis.read(buffer)) > 0) {
                    zos.write(buffer, 0, len);
                }
            }
        } else if (file.isDirectory()) {
            File[] children = file.listFiles();
            if (children != null) {
                for (File child : children) {
                    addFileToZip(zos, child, parentDir);
                }
            }
        }

        zos.closeArchiveEntry();
    }

    public static void unpackModule(String zipFile, String moduleDir) {
        try (ZipFile zip = new ZipFile(zipFile)) {
            Enumeration<ZipArchiveEntry> entries = zip.getEntries();

            while (entries.hasMoreElements()) {
                ZipArchiveEntry entry = entries.nextElement();
                File file = new File(moduleDir, entry.getName());

                if (entry.isDirectory()) {
                    file.mkdirs();
                } else {
                    file.getParentFile().mkdirs();
                    try (InputStream is = zip.getInputStream(entry)) {
                        try (OutputStream os = new FileOutputStream(file)) {
                            byte[] buffer = new byte[1024];
                            int len;
                            while ((len = is.read(buffer)) > 0) {
                                os.write(buffer, 0, len);
                            }
                        }
                    }
                }
            }
        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}
