import java.util.zip.*;

public class ZipExtractor {

    /**
     * Extracts files from a ZIP archive to a specified directory.
     * 
     * @param zipFilePath The path to the ZIP file.
     * @param destinationDir The directory to extract the files to.
     * @param safeMode If true, checks for existing files and skips them.
     * @throws IOException If an I/O error occurs.
     */
    public static void extractZip(String zipFilePath, String destinationDir, boolean safeMode) throws IOException {
        Path destDirPath = Paths.get(destinationDir);
        if (!Files.exists(destDirPath)) {
            Files.createDirectories(destDirPath);
        }

        try (ZipInputStream zis = new ZipInputStream(new FileInputStream(zipFilePath))) {
            ZipEntry entry = zis.getNextEntry();
            while (entry != null) {
                Path filePath = destDirPath.resolve(entry.getName());
                if (entry.isDirectory()) {
                    Files.createDirectories(filePath);
                } else {
                    if (safeMode && Files.exists(filePath)) {
                        System.out.println("Skipping existing file: " + filePath);
                        continue;
                    }
