Here's a simple Node.js script using the built-in `http` and `fs` modules to create a HTTP server that streams requested files to the client. This script includes basic sanitization of the file path to prevent directory traversal attacks.

```javascript
const http = require('http');
const fs = require('fs');
const path = require('path');

const server = http.createServer((req, res) => {
    // Extract the requested file path from the URL
    let filePath = req.url === '/' ? 'index.html' : req.url.substring(1);

    // Sanitize the file path to prevent directory traversal
    filePath = path.join(__dirname, 'public', filePath);

    // Ensure the requested file is within the 'public' directory
    if (!filePath.startsWith(path.join(__dirname, 'public'))) {
        res.statusCode = 403;
        res.end('Forbidden');
        return;
    }

    // Check if the requested file exists
    fs.stat(filePath, (err, stats) => {
        if (err) {
            if (err.code === 'ENOENT') {
                // File does not exist
                res.statusCode = 404;
                res.end('Not Found');
            } else {
                // Other error
                res.statusCode = 500;
                res.end('Internal Server Error');
            }
            return;
        }

        // Stream the file to the client
        const fileStream = fs.createReadStream(filePath);
        fileStream.pipe(res);

        fileStream.on('error', (err) => {
            res.statusCode = 500;
            res.end('Internal Server Error');
        });
    });
});

const PORT = process.env.PORT || 3000;
server.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});
```

In this script:

- We create an HTTP server using `http.createServer`.
- The requested file path is extracted from the URL and sanitized using `path.join` and `path.startsWith` to ensure it's within a designated directory (`public` in this case).
- We check if the requested file exists using `fs.stat`.
- If the file exists, we create a readable stream of the file and pipe it to the HTTP response.
- If there's an error (file not found or other), we handle it appropriately and send an appropriate HTTP status code and message.

Remember to replace `'public'` with the directory where your files are stored. Also, ensure that the directory is properly secured and not accessible via the web if it contains sensitive files.

