  console.log(`Server is running on http://localhost:${port}`);
});

// Start the livereload server
liveReloadServer.server.once('connection', () => {
  setTimeout(() => {
    liveReloadServer.refresh('/');
  }, 100);
});
```

This code sets up a Node.js server that listens on port 3000. It serves static files from the 'public' directory and handles routes for '/about' and '/contact'. The server also includes a live reload feature using the 'livereload' package, which refreshes the browser when files in the 'public' directory are changed.

