import logging
from typing import Dict, Optional

class SystemResourceLimits:
    def __init__(self, max_connections: int, max_memory_usage: int, max_file_descriptors: int):
        self.max_connections = max_connections
        self.max_memory_usage = max_memory_usage
        self.max_file_descriptors = max_file_descriptors

    def evaluate_limits(self, current_keys: int) -> bool:
        # Evaluate if the number of current keys exceeds the system resource limits
        if current_keys > self.max_connections:
            logging.warning("Number of keys exceeds maximum connections limit.")
            return False
        if current_keys * 1024 > self.max_memory_usage:
            logging.warning("Total memory usage exceeds maximum memory limit.")
            return False
        if current_keys > self.max_file_descriptors:
            logging.warning("Number of keys exceeds maximum file descriptors limit.")
            return False
        return True

class Service:
    def __init__(self, resource_limits: SystemResourceLimits):
        self.resource_limits = resource_limits
        self.accepted_keys: Dict[str, int] = {}

    def add_key(self, key: str) -> bool:
        # Check if adding the key would exceed the system resource limits
        if not self.resource_limits.evaluate_limits(len(self.accepted_keys) + 1):
            return False
        self.accepted_keys[key] = 1
        return True

    def remove_key(self, key: str) -> bool:
        # Remove a key and check if the system resource limits are still respected
        if key in self.accepted_keys:
            del self.accepted_keys[key]
            return True
        return False

# Example usage
resource_limits = SystemResourceLimits(max_connections=1000, max_memory_usage=1024000, max_file_descriptors=2048)
service = Service(resource_limits)

# Adding keys
for i in range(1500):
    if not service.add_key(f"key{i}"):
        logging.error("Failed to add key, exceeding resource limits.")
        break

# Removing keys
for key in list(service.accepted_keys.keys()):
    if not service.remove_key(key):
        logging.error("Failed to remove key.")
```

