// Function to create a TCP socket and connect to the server
int create_tcp_socket(const char *hostname, int port) {
    int sockfd;
    struct addrinfo hints, *res, *p;
    int status;

    memset(&hints, 0, sizeof hints);
    hints.ai_family = AF_UNSPEC; // Use IPv4 or IPv6, whichever is available
    hints.ai_socktype = SOCK_STREAM;

    if ((status = getaddrinfo(hostname, NULL, &hints, &res)) != 0) {
        fprintf(stderr, "getaddrinfo error: %s\n", gai_strerror(status));
        return -1;
    }

    // Attempt to connect to each address until one succeeds
    for (p = res; p != NULL; p = p->ai_next) {
        if ((sockfd = socket(p->ai_family, p->ai_socktype, p->ai_protocol)) == -1) {
            perror("socket");
            continue;
        }

        // Set the port number
        ((struct sockaddr_in *)p->ai_addr)->sin_port = htons(port);

        if (connect(sockfd, p->ai_addr, p->ai_addrlen) == -1) {
            close(sockfd);
            perror("connect");
            continue;
        }

        break; // If we get here, we've successfully connected
    }

    freeaddrinfo(res); // Free the linked list

    if (p == NULL) {
        fprintf(stderr, "Failed to connect\n");
        return -1;
    }

    return sockfd;
}

int main(int argc, char *argv[]) {
    if (argc < 3) {
        fprintf(stderr, "Usage: %s <hostname> <port>\n", argv[0]);
        return 1;
    }

