#include <poppler/cpp/poppler-document.h>
#include <poppler/cpp/poppler-page.h>
#include <poppler/cpp/poppler-annotation.h>
#include <iostream>

void addBookmark(poppler::document *doc, int pageNumber, const std::string &bookmarkName) {
    if (pageNumber < 1 || pageNumber > doc->pages()) {
        std::cerr << "Invalid page number: " << pageNumber << std::endl;
        return;
    }

    poppler::page *page = doc->create_page(pageNumber - 1); // Pages are 0-indexed in Poppler

    if (!page) {
        std::cerr << "Failed to create page: " << pageNumber << std::endl;
        return;
    }

    // Create a bookmark annotation
    poppler::annotation *bookmark = poppler::annotation::create_link_annotation(
        poppler::rectangle(0, 0, 0, 0), // No rectangle for bookmarks
        poppler::link_annotation_destination::create_page_destination(pageNumber - 1)
    );

    // Set the bookmark name
    bookmark->set_title(bookmarkName.c_str());

    // Add the bookmark to the document
    doc->add_annotation(bookmark);

    // Clean up
    delete page;
    delete bookmark;
}

int main() {
    // Load the PDF document
    poppler::document *doc = poppler::document::load_from_file("example.pdf");

    if (!doc) {
        std::cerr << "Failed to load PDF document" << std::endl;
        return 1;
    }

    // Add a bookmark to the first page
    addBookmark(doc, 1, "First Page");

    // Save the document with the new bookmark
    doc->save("example_with_bookmark.pdf");

    // Clean up
    delete doc;

    return 0;
}
